// --- Validation Utilities ---

function isValidAddress(address) {
  try {
    return ethers.isAddress(address);
  } catch {
    return false;
  }
}

function isChecksumAddress(address) {
  try {
    return ethers.getAddress(address) === address;
  } catch {
    return false;
  }
}

function validateAndChecksumAddress(address, label = "address") {
  if (typeof address !== "string") {
    throw new Error(`Invalid ${label}: must be a string`);
  }
  const trimmed = address.trim();
  if (!isValidAddress(trimmed)) {
    throw new Error(`Invalid ${label}: not a valid Ethereum address`);
  }
  return ethers.getAddress(trimmed);
}

function isAllowlistedDex(routerAddress) {
  const checksummed = ethers.getAddress(routerAddress);
  return Object.values(KNOWN_DEX_CONTRACTS).includes(checksummed);
}

function isAllowlistedToken(tokenAddress) {
  const checksummed = ethers.getAddress(tokenAddress);
  return Object.values(KNOWN_TOKENS).includes(checksummed);
}

function validateAmount(amount, decimals) {
  if (typeof amount !== "string" && typeof amount !== "number") {
    throw new Error("Amount must be a string or number");
  }
  const amountStr = String(amount);

  // Prevent scientific notation and invalid characters
  if (!/^\d+\.?\d*$/.test(amountStr)) {
    throw new Error("Invalid amount format");
  }

  const parsed = ethers.parseUnits(amountStr, decimals);
  if (parsed <= 0n) {
    throw new Error("Amount must be greater than zero");
  }
  return parsed;
}

function validateSlippage(slippageBps) {
  if (typeof slippageBps !== "number" || !Number.isInteger(slippageBps)) {
    throw new Error("Slippage must be an integer (basis points)");
  }
  // Max 5% slippage (500 bps) to protect users
  if (slippageBps < 1 || slippageBps > 500) {
    throw new Error("Slippage must be between 1 and 500 basis points (0.01% - 5%)");
  }
  return slippageBps;
}

function validateDeadlineMinutes(minutes) {
  if (typeof minutes !== "number" || !Number.isInteger(minutes)) {
    throw new Error("Deadline must be an integer (minutes)");
  }
  // Between 1 and 30 minutes
  if (minutes < 1 || minutes > 30) {
    throw new Error("Deadline must be between 1 and 30 minutes");
  }
  return minutes;
}

function validatePath(path) {
  if (!Array.isArray(path) || path.length < 2 || path.length > 4) {
    throw new Error("Swap path must be an array of 2-4 token addresses");
  }
  return path.map((addr, i) => validateAndChecksumAddress(addr, `path[${i}]`));
}

// --- Secure Approval: NEVER approve unlimited amounts ---

/**
 * SECURITY: Approve only the exact amount needed for the swap.
 *
 * Approving MaxUint256 is a well-known DeFi anti-pattern that exposes users
 * to unlimited token drainage if the approved contract is compromised or
 * contains a vulnerability. We approve only the exact swap amount.
 */
function calculateExactApproval(swapAmount) {
  // SECURE: Only approve the exact amount needed
  // NEVER use ethers.MaxUint256 or type(uint256).max
  if (swapAmount <= 0n) {
    throw new Error("Approval amount must be positive");
  }
  return swapAmount;
}

